def test_code_javascript_basic() -> None:
    """Smoke test: JavaScript source code file extraction"""

    document_path = helpers.resolve_document("code/app.js")
    if not document_path.exists():
        pytest.skip(f"Skipping code_javascript_basic: missing document at {document_path}")

    config = helpers.build_config(None)

